type Candidate = { cell: Cell; neighborCount: number };

export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const candidates = new Map<string, Candidate>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const existing = candidates.get(key);
      candidates.set(key, {
        cell: neighbor,
        neighborCount: (existing?.neighborCount ?? 0) + 1,
      });
    }
  }

  const survives = (key: string, neighborCount: number): boolean =>
    neighborCount === 3 || (neighborCount === 2 && aliveKeys.has(key));

  return [...candidates]
    .filter(([key, { neighborCount }]) => survives(key, neighborCount))
    .map(([, { cell }]) => cell);
}

