type NeighborTally = { cell: Cell; count: number };

const tallyNeighbors = (cells: Cell[]): Map<string, NeighborTally> => {
  const tallies = new Map<string, NeighborTally>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const tally = tallies.get(key);
      if (tally) {
        tally.count += 1;
      } else {
        tallies.set(key, { cell: neighbor, count: 1 });
      }
    }
  }
  return tallies;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const tallies = tallyNeighbors(cells);
  const survives = (key: string, count: number): boolean =>
    count === 3 || (count === 2 && aliveKeys.has(key));

  const survivors: Cell[] = [];
  for (const [key, { cell, count }] of tallies) {
    if (survives(key, count)) survivors.push(cell);
  }
  return survivors;
}

